import './TabbarItem.scss';

import { Icon } from ':components/Icon';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import React, { isValidElement } from 'react';

import type { TabbarItemProps } from './TabbarItem.types';

export const TabbarItem: React.FC<TabbarItemProps> = ({
	className,
	type,
	iconName,
	label,
	active,
	onClick,
	routingComponent,
	disabled,
}) => {
	const WrapItem = item =>
		isValidElement(routingComponent) ? React.cloneElement<any>(routingComponent, {}, item) : item;

	return WrapItem(
		<li
			role="button"
			tabIndex={onClick ? 0 : undefined}
			className={classNames(
				'dsb_tabbarItem',
				`dsb_tabbarItem-${type}`,
				active && 'dsb_tabbarItem-active',
				disabled && 'dsb_tabbarItem-disabled',
				className,
			)}
			onClick={onClick}
			onKeyDown={
				onClick
					? event => {
							if (event.key === 'Enter' || event.key === ' ') {
								event.preventDefault();
								// Создаем синтетическое событие мыши для передачи в onClick
								const mouseEvent = new MouseEvent('click') as unknown as React.MouseEvent;
								onClick(mouseEvent);
							}
						}
					: undefined
			}
		>
			<Icon iconName={iconName} size={type === 'default' ? 'large' : 'small'} className="dsb_tabbarItem__icon" />
			{type === 'default' && (
				<Typography variant="caption" className="dsb_tabbarItem__label">
					{label}
				</Typography>
			)}
		</li>,
	);
};

export type { TabbarItemProps };
